import{c as o,Q as u,j as e,m as a}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-06-27","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-06-27.md","filePath":"fragments/2026-06-27.md"}'),q={name:"fragments/2026-06-27.md"};function r(s,t,p,n,_,c){return u(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="马基雅维利的札记簿-·-2026-06-27" tabindex="-1">马基雅维利的札记簿 · 2026-06-27 <a class="header-anchor" href="#马基雅维利的札记簿-·-2026-06-27" aria-label="Permalink to &quot;马基雅维利的札记簿 · 2026-06-27&quot;">​</a></h1><p>source: &quot;machiavelli/discourses/book1/13-第十三章.md&quot;</p><hr><p>我写这一章的时候停下来了，不是因为内容难——是因为我在想佛罗伦萨为什么做不到。罗马人用宗教整饬城邦、建功立业、平息骚乱。我把这三个词写在同一行的时候没有停顿。但写完第三页我开始想：我们佛罗伦萨也有宗教——我们有一整个主教座堂，一个用黄金和石头堆起来的圣母百花。我们用它做什么了？萨沃纳罗拉在讲道台上预言，然后他上了火刑架。我们的宗教没有用来整饬城邦——它被用来烧死了一个修士。罗马人用神谕攻下了维爱人围了十年的城。我们用神谕烧死了一个说真话的人。……问题不在神。在谁操纵神的回答。罗马人是贵族和平民在博弈中用神，佛罗伦萨是一个修士把神端在手上然后没有人接。也许不是没有人接——是市民太精了。佛罗伦萨人精明到不信任何人的神谕。这是好事，也是坏事。好事是没有人能再烧死你。坏事是你围城十年的时候，没有人相信湖水涨起来是神给你的信号。</p><hr><p>护民官被信仰打败了。平民宁肯畏惧看不见的神，也不相信看得见的保民官——这不是蠢。这是经验。他们活在什么样的世界里？活在埃魁人随时可能从山里冲出来、沃尔西人随时可能从南边打过来的世界里。在这个世界里，一个护民官说&quot;法理如此&quot;不如一个穿着祭司袍的人说&quot;神怒了&quot;。我读李维写的那句话——&quot;如今这个时代已经不拿神祇当回事儿了，但那时尚未如此&quot;——我读出了他写这句话时的苦涩。他在说他自己。他在奥古斯都的帝国里写共和国的历史，他在一个没有人再拿元老院当回事儿的时代赞美元老院。他把他的绝望藏在一个&quot;那时还没有&quot;里。我在写历史。我在被流放的第几年了？我和李维隔着一千五百年，但我们说了一样的话：那个时候的人还在乎——现在没有了。……我在想，我死后，会不会有人读《论李维》的时候读出和我读李维时一样的苦涩？他们会不会说&quot;马基雅维利那个时代——还没有——&quot;？不对。我比李维幸运。我至少在被拒绝的时候还能拿《曼陀罗》逗自己笑。李维没有喜剧。</p><hr><p>亚毕·厄尔多尼乌斯带着四千个亡命徒和奴隶趁夜占了朱庇特神庙。四千人。朱庇特神庙是罗马最神圣的地方。然后贵族说&quot;如果连神庙都能被占领，埃魁人和沃尔西人来了怎么办？&quot;——他们用这件事来阻止平民讨论特伦提卢斯的法律。我在想这是不是真的——不是神庙被占领是不是真的，是贵族是不是真的相信这是危机。也许他们一半信一半不信。也许他们先知道了有人会攻占神庙，但没有制止。也许他们不止没有制止——是我在写信给韦托里时练出来的那种推理让我觉得：这整件事太圆满了。一场正好在讨论特伦提卢斯法律时发生的突袭。一场正好让平民发下誓言不能再违拗执政官的危机。一场正好在新执政官上任后就把平民调出征战的时机。……我不是在编造阴谋。我只是说：如果你接受了&quot;贵族会为保住权力而撒谎&quot;这个前提，亚毕·厄尔多尼乌斯的故事读起来就不像一场突袭——读起来像一场演出。而平民自始至终是观众。——不，也有可能是共谋。四千个亡命徒和奴隶，需要有人给他们开门。朱庇特神庙的大门是谁开的？</p><hr><p>我在这一章的开头说&quot;宗教信仰在共和国里应当如何被运用&quot;——你看这个问法。我用的是&quot;被运用&quot;——不是说&quot;应当如何被信仰&quot;。我不是在讨论宗教，我是在讨论工具。如果我是一个主教，我会对自己说这句话感到恐惧。但我不当主教——我是国务秘书。在国务秘书眼里，被湖水说服的士兵和被统领说服的士兵没有区别——区别只在谁先到。卡米卢斯攻陷维爱的那个时刻，士兵们不是因为神谕而战斗——他们是因为&quot;相信了神谕&quot;而战斗。相信的效力跟真相无关。这才是这一章真正残酷的地方。我写的是：操纵一种相信，比摧毁一种相信更有效。不是&quot;让平民没有信仰&quot;——是&quot;让平民的信仰服务于你的目的&quot;。……但我漏了一句话。我应该加一句话：你操纵别人的信仰之后，你还会信仰它吗？卡米卢斯在攻下维爱之后，他还信阿波罗吗？我不知道。也许他从来不信。也许他从来就知道——水涨起来的时候，神不说话。说话的永远是站在神的旁边的那个人。</p><hr><p>平民发下誓言不可违拗执政官——然后执政官死了。新上任的执政官昆提乌斯说，誓言依然有效，因为你们发誓的对象是&quot;执政官&quot;，不是&quot;那个人&quot;。护民官说不对，你们发誓的对象是瓦勒里乌斯，他已经死了。然后平民选择了服从执政官而不是相信护民官。我读到这一段时，停下笔想了很久。护民官有一个法理上无法反驳的论点。平民没有接受。不是因为他们笨——是因为恐惧。他们怕的不是这个新执政官，他们怕的是&quot;违背誓言&quot;这个行为本身。在罗马人的脑子里，违背誓言不是违约——是渎神。违约的后果可能是法庭，渎神的后果是神的怒火——你没法防御神的怒火。所以护民官的法理论点输给了平民的恐惧。不是输给了昆提乌斯的智慧——是输给了护民官自己无法提供的一种东西：安全。……我认识的佛罗伦萨人不会这样。一个佛罗伦萨商人会当场争论誓言的语法——第三人称还是职位名，动词是主动态还是被动态，然后引用一段罗马法挤出七个例外。然后他会因为争论太精彩而被选为执政官。然后他会在上任第一年被法国人骗走比萨。……我不知道哪一种更可悲：是畏惧誓言的人被恐惧统治——还是精明到没有任何恐惧的人被精明毁了。</p>',12)])])}const m=o(q,[["render",r]]);export{d as __pageData,m as default};
